from pydantic import BaseModel

from .permissions import Permission
from .roles import Role, mock_roles


class User(BaseModel):
    firstname: str
    lastname: str
    image: bytes
    email: str
    modules: list[str|None]
    roles: list[Role]
    permissions: set[Permission | None]

    def merge_permissions_with_roles(self) -> set[Permission | None]:
        merged = set(self.permissions)
        for role in self.roles:
            merged.update(role.permissions)
        self.permissions = merged
        return merged


user1 = User(
    firstname="Thibault",
    lastname="MOREZ",
    image=b'data:image/png;base64,',
    email="thibault.morez@epitech.eu",
    modules=[],
    roles = mock_roles(),
    permissions=set([])
)
user1.merge_permissions_with_roles()

print(user1.permissions)
